(window.webpackJsonp=window.webpackJsonp||[]).push([[57],{684:function(n,r){n.exports="\x3c!-- \r\ntitle: 01-PowerShell入门\r\nsort: \r\n--\x3e \r\n# PowerShell入门\r\n\r\n## 特性\r\n\r\n- 输出基于对象而非文本\r\n\r\n- 本机命令称为 cmdlet，可扩展\r\n\r\n- 命令帮助：`-?`\r\n\r\n- 列出包含特定谓词的所有命令\r\n\r\n  ```powershell\r\n  Get-Command -Verb Get\r\n  ```\r\n\r\n- `Get-Alias` cmdlet 显示别名的真实名称。\r\n\r\n## 使用\r\n\r\n示例缩写：\r\n\r\n| 名词或谓词 | 缩写 |\r\n| :--------- | :--- |\r\n| get        | g    |\r\n| Set        | s    |\r\n| Item       | i    |\r\n| local      | l    |\r\n| Command    | cm   |\r\n| Alias      | al   |\r\n\r\n- 例子\r\n\r\n  ```\r\n  sal -name ll -value ls\r\n  ```\r\n\r\n\r\n### 存储对象\r\n\r\n```powershell\r\n$loc\t# 创建变量\r\n$loc = Get-Location\t\t# 将命令输出传给变量\r\n```\r\n\r\n### 管道\r\n\r\n```powershell\r\nGet-ChildItem -Path C:\\windows\\system32 | Out-Host -Paging\r\n# 分页显示\r\n```\r\n\r\n"}}]);